var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고모님이…… 할아버님이라고요?","JPN":"叔母様が……お祖父様ですって？","ENG":"Y-you’re... Grandfather?","TWN":"姑姑……是爺爺？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"말했었잖니, 지아야.","JPN":"言ったじゃないか、ユイ。","ENG":"Didn’t I tell you already, Jia?","TWN":"我不是跟你說嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"조만간 그 병실에서 일어나 쌩쌩하게 걸어 다닐 거라고.","JPN":"近いうちにあの病室を出て、元気に歩けるようになると。","ENG":"I’ll soon get better and walk out of this place.","TWN":"爺爺很快就會康復出院的。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 말……. 할아버님께서 종종 하시던…….","JPN":"その言葉……お祖父様が度々話していた……","ENG":"That’s... what Grandfather used to say...","TWN":"那句話……爺爺常掛在嘴邊……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"설마, 정말 할아버님……?","JPN":"まさか、本当にお祖父様……？","ENG":"A-are you really Grandfather...?","TWN":"難道你真的是爺爺……？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"속지 마세요, 리더. 단순한 성문 변조기에 불과합니다.","JPN":"騙されないでください、リーダー。単なるボイスチェンジャーにすぎません。","ENG":"Don’t be fooled, Leader. She’s just using a voice modulator.","TWN":"老大，你別上當，那不過就是變聲器而已！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"저 자는 회장이 아니에요. 음성으로 혼란을 야기하는 건 흔한 속임수예요.","JPN":"あれは会長ではありません。音声で惑わすのはよくあるトリックです。","ENG":"She’s not the President. It’s another one of her tricks to cause confusion.","TWN":"她不是會長！利用聲音來引起混亂是常見的詐騙手法。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"초원이 말이 맞아! 회장님은 죽은 지 한참 지났잖아!","JPN":"ナオちゃんの言うとおりだよ！　会長はずっと昔に亡くなってるじゃん！","ENG":"Chowon’s right! The President passed away a long time ago!","TWN":"初源說得沒錯！會長都已經過世這麼久了！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"그렇다, 대장. 아무리 그리워도 죽은 사람은 두 번 다시 돌아오지 않아.","JPN":"そのとおりだ、隊長。どんなに恋しくても、死んだ人間は二度と戻らない。","ENG":"She’s right, Cap. The dead don’t come back to life, no matter how much you miss them.","TWN":"沒錯，隊長。我知道你很想念會長，但死人是不會復活的。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"덜떨어진 머저리들. 네놈들이 모르는 건 세상에 없는 줄 아나?","JPN":"アルファトリックス・イノベーションは間抜けどもの寄せ集めかしら。\\nあんたたちが知らないことはこの世にないとでも？","ENG":"Fools! You think you know everything there is to know about this world?","TWN":"愚昧的傢伙們！你們不知道，不代表就不存在於這個世界上。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"나는 회장의 생전 기억과 경험을 전부 이식했다.","JPN":"この体には会長の生前の記憶と経験をすべて移植した。","ENG":"I have all of my father’s memories and experiences implanted in my head.","TWN":"我移植了會長生前的全部記憶和經驗。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"워낙 분량이 방대해서 아직도 완전히 정착하진 않았지만…….","JPN":"あまりにも量が膨大で、まだ完全に定着していないけど……","ENG":"Although it hasn’t fully set in as it is a vast amount of data...","TWN":"不過因為量有點龐大，所以還沒完全載入……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"기억은 인간을 구분하는 중요한 요소이니, 나도 우리 아빠를…….","JPN":"記憶は人間を区分する重要な要素だから、私も父さんを……","ENG":"Since memory is a core part of what distinguishes a human being... it's not strange to claim...","TWN":"記憶是分辨人的其中一個要素，因此我以爸爸……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아니, 죽은 알파트릭스의 회장을 자처해도 이상하지 않지.","JPN":"いや、亡きアルファトリックスの会長を自任してもおかしくないわ。","ENG":"That I am still my father, no, the late President of Alphatrix.","TWN":"不對，我以死去的阿爾法崔克斯會長自居，一點也不奇怪。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"TWN":"　　"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"회장은 네게 자기도 어릴 적 부모를 잃었다고 말했지?","JPN":"会長はあんたに自分も幼い頃両親を亡くしたと言ったわよね？","ENG":"The President told you that he lost his parents at an early age, didn’t he?","TWN":"會長是不是跟你說過，他和你一樣從小便失去父母？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"회장은 두려움에 겨워 기억을 묻어 뒀지만, 나는 알 수 있어.","JPN":"会長は恐怖に耐えきれず記憶を心の奥底にしまっていたけど、\\n私にはわかるわ。","ENG":"Although he may have blocked out that memory, I still remember it.","TWN":"雖然會長因為太害怕而將這段記憶埋才起來，但我還是可以知道。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그건 분명 침식 재난이었어. 그 땐 관리국이 없어서 그런 용어 자체가 없었지만.","JPN":"あれは確かに侵食災害だった。\\nあの時は管理局がなくて、そんな用語自体がなかったけど。","ENG":"It was a Corruption disaster. But back then, there wasn’t anything called the Administration.","TWN":"是因為侵蝕災難的關係，只是當時還沒有管理局，還沒有這個說法。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 이야기는……. 고모님은 정말로 할아버님의 기억을…….","JPN":"その話は……叔母様は本当にお祖父様の記憶を……","ENG":"The story... So you really do have his memories...","TWN":"姑姑……真的將爺爺的記憶……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"원인 모를 괴생명체의 습격에서 살아남은 뒤로 회장은 변했어.","JPN":"得体の知れない怪生命体の襲撃から生き延びた後、会長は変わった。","ENG":"He changed after surviving an attack from an unknown monster.","TWN":"當他從奇怪生物的攻擊中倖存下來後，他整個人都變了。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"세상을 몰랐기에 두려워할 필요도, 걱정할 필요도 없던 자신의 어린 시절처럼……","JPN":"世間を知らなかったから恐れる必要も心配する必要もなかった\\n自身の子ども時代のように……","ENG":"He devoted his entire life to making the world a better place...","TWN":"他將他的一生都用來打造一個不需要害怕，也不需要擔心的世界…"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"더 나은 세상을 만드는 데 평생을 매달렸지.","JPN":"より良い世界を作ることに一生をかけた。","ENG":"Just as how it was when he was a child... When he had nothing to fear or worry about.","TWN":"就像他小時候認識的那個世界一樣。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그 때부터 돈을 모으기 시작한 거야. 인간으로는 삼류 쓰레기지만, 돈 버는 재주는 남달랐으니까.","JPN":"あの時から金を集め始めたのよ。人間としては三流のゴミ同然だけど、\\n儲ける才能は並み外れていたからね。","ENG":"That’s when he started to save up money. He was a scumbag, but he did have a gift for making himself rich.","TWN":"他就是從那時候開始拼命賺錢的，身為一個人他不過就是個垃圾，但他確實非常會賺錢！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"경쟁 기업을 무너뜨리고, 직원들을 죽을 만큼 혹사시키고, 자기 아내와 자식들까지 돈벌이에 이용하면서…….","JPN":"ライバル企業を倒産させ、従業員たちを死ぬほど酷使して、\\n自分の妻や子どもたちまで金儲けに利用してまで……","ENG":"He took out competitors, treated his employees like tools, and even used his wife and child as a source of income...","TWN":"不只打垮競爭對手，讓員工們做得要死，還利用自己的妻子和小孩賺錢……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"하지만 그 인간에게는 처음부터 무리였어. 바꿔 말하면 돈 버는 재주밖에 없었거든.","JPN":"でも、あいつには最初から無理だった。言い換えれば、金を稼ぐ才能しかなかったのよ。","ENG":"But it was doomed from the start. In other words, his only skill was making money.","TWN":"但他根本從一開始就辦不到，換句話說，他就只會賺錢而已。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"회장은 널 소중히 여긴 게 아냐.","JPN":"会長はあんたを大切にしていたわけじゃない。","ENG":"The President didn’t think of you as special.","TWN":"會長並不是看重你，"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그저 자기 미련을 대신 이뤄 줄 누군가가 필요했을 뿐이지.","JPN":"ただ、自分の未練を代わりに叶えてくれる誰かが必要だっただけなのよ。","ENG":"He just saw you as a means to achieve his unfulfilled dreams.","TWN":"他只是需要一個，能夠代替他達成心願的對象而已。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"쟤들……! 리더랑 얼굴이 똑같아!","JPN":"あの子たち…！　リーダーと同じ顔をしてる！","ENG":"Look...! Those things all look like Leader!","TWN":"他們……！長得都和老大一模一樣！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"응. 저것들이 그 클론인가 봐.","JPN":"そうですね。あれが例のクローンでしょうか。","ENG":"Uh-huh. I’m guessing those are the clones.","TWN":"嗯，他們應該都是複製人。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"전부 밸런스 브레이커로 무장하고 있어. 너도 평소처럼 튀어나가면 벌집이 될 거야.","JPN":"全員バランスブレイカーで武装しています。\\nアサネ、いつもどおりに飛び出したらハチの巣にされますよ。","ENG":"They’re all equipped with Balance Breakers. Watch out, or you’ll become Swiss cheese.","TWN":"他們全都有裝載平衡破壞者，你再跟平時一樣輕舉妄動很可能會變成蜂窩。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"네가 하나 틀린 게 있어. 신지아.","JPN":"あんたは一つ間違っているわ、ヒメノ・ユイ。","ENG":"You’re wrong about one thing, Shin Jia.","TWN":"沈佳，你弄錯一件事。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L8_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"여기 있는 것들은 모두 회장이 폐기했던…… 나와 같은 실패작들이야.","JPN":"ここにあるモノはすべて会長が廃棄した……私と同じ失敗作よ。","ENG":"Everything here was discarded by the President... They’re all failed projects, just like me.","TWN":"現在在場的全都是會長不要的……和我一樣是個失敗品。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L9_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"가능성을 인정 받은 단 하나의 개체를 제외하곤 말이지.","JPN":"可能性を認められた、たった一体の個体を除いてね。","ENG":"Well, all except for one unit.","TWN":"當然不包括那唯一一個，可能性受到肯定的個體。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 개체가……. 저군요.","JPN":"その個体が……私だったのですね。","ENG":"I assume that’s me...","TWN":"那個個體……就是我吧？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"리더, 대치 중입니다. 적의 말에 귀 기울이지 마세요.","JPN":"リーダー、対峙中です。敵の発言に耳を傾ける必要はありません。","ENG":"Leader, we’re in position. Don’t listen to her lies.","TWN":"老大，現在在對峙中，千萬不能受敵人的話影響！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 혁신의 밤 전날에 봤어요.","JPN":"いいえ。革新の夕べの前日に見ました。","ENG":"No, I saw them the day before the Night of Innovation.","TWN":"不是的，在革新之夜的前一天我有看到。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여기와 비슷한 풍경에 소독약 냄새, 그리고 할아버님의 목소리…….","JPN":"ここと似た風景に消毒薬の臭い、そしてお祖父様の声……","ENG":"A place similar to this with a faint smell of antiseptics, and Grandfather’s voice...","TWN":"和這裡類似的景象，加上消毒水的味道，還有爺爺的聲音……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"회장은 널 애지중지했지.","JPN":"会長はあんたを大事にしてたわね。","ENG":"The President cared about you deeply.","TWN":"會長非常疼愛你對吧？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L19_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"하지만 결국 그건 네가 말 잘 듣고 유능한 기물이었기 때문이야.","JPN":"でも結局、それはあんたが言うことをよく聞いてくれる有能な駒だったからよ。","ENG":"But that was because you were an obedient and powerful pawn of his.","TWN":"但那也只不過是因為，你是一顆聽話又能幹的棋子。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"자기 뜻 따위는 없고, 말하는 대로 따르기만 하는.","JPN":"自分の意志なんかない、言う通りに従うだけの。","ENG":"You have no self-meaning, and only do as you’re told.","TWN":"沒有自己的主見，只會聽命行事。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L21_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그 인간에게는! 그 쓰레기에게는 결국 너도 자기 망상을 이뤄 줄 수단에 불과했다고!","JPN":"あいつには！　あのクズには結局あんたも自分の妄想を叶える手段に\\nすぎなかったのよ！","ENG":"To him! That piece of trash saw you as a means to his end!","TWN":"對那個人！對那個垃圾而言，你不過就是能替他完成幻想的工具！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……아뇨. 고모님은 모르고 계세요.","JPN":"……いいえ。叔母様にはわからないでしょう。","ENG":"No, Auntie... You’re wrong.","TWN":"……不是的，姑姑你不知道。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님은 절 아껴 주셨어요. 진심으로.","JPN":"お祖父様は私を大切にしてくれました。心から。","ENG":"Grandfather loved me with all his heart.","TWN":"爺爺是真心在疼愛我的。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭐……?","JPN":"なんですって……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"내가……. 그 아이에게 너무…… 큰 잘못을…….","JPN":"私は……あの子にあまりにも……大きな過ちを……","ENG":"I... big mistake... to her...","TWN":"我……對那孩子……犯下很嚴重的錯誤……"},"stage":{"bg":"ALPHA_01","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그런데도……. 그 아이는……. 나만…….","JPN":"それでも……あの子は……私だけを……","ENG":"But she... still... only me...","TWN":"但……那孩子……對我……"},"stage":{"bg":"ALPHA_01","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"웃기지 마! 대체 뭘 믿고 그딴 헛소리를 지껄여!","JPN":"ふざけるな！　いったい何を根拠にそんなうわごとが言えるの！？","ENG":"Nonsense! You must be insane to think that!","TWN":"笑死人！你憑什麼在那邊胡說八道！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 저는, 할아버님의 수단이 아니에요.","JPN":"そして私は、お祖父様の駒ではありません。","ENG":"Also, I wasn’t a means to his end.","TWN":"而且我並不是爺爺的工具。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제 소중한 분들이…….","JPN":"私の大切な人たちが……","ENG":"If I could...","TWN":"要是能夠打造出一個……"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"두려워할 필요도, 걱정할 필요도 없는 세상을 만들 수 있다면.","JPN":"恐れる必要も、心配する必要もない世界を作ることができるのなら。","ENG":"Make the world a place without fear or worries...","TWN":"我在乎的人都不需要害怕或擔心的世界，"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저는 기꺼이 그렇게 하겠어요.","JPN":"私は喜んでそうします。","ENG":"I will gladly do as I was told.","TWN":"那我非常樂意這麼做。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님이 아니라, 제 의지로요.","JPN":"お祖父様ではなく、私の意志で。","ENG":"Not because Grandfather told me to, but of my own will.","TWN":"不是因為爺爺，而是我自己想這麼做！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"큭…… 크큭……!","JPN":"クッ……ククッ……！","ENG":"Hah... Hah hah...!","TWN":"哼……哼哼……！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L42_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아하하하하하하하!!","JPN":"アハハハハハハハ！！","ENG":"Ahahahaha!!","TWN":"哈哈哈哈哈哈！！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L43_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아빠, 내 머릿속에서 잘 듣고 있어?","JPN":"父さん、私の頭の中で今の話を聞いてる？","ENG":"Daddy, did you hear that?!","TWN":"爸，你在我腦袋裡有聽到嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L44_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아빠는 성공했네! 이렇게 말 잘 듣는 손녀를 뒀으니까!","JPN":"父さんは成功したね！　こんなに言うことをちゃんと聞く孫娘がいるんだから！","ENG":"You were successful! Look how well your granddaughter actually listens to you!!","TWN":"爸你成功咧！有一個這麼聽話的孫女！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L45_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그런데 지아야, 이를 어쩌나?","JPN":"でもね、ユイちゃん。とても残念だわ。","ENG":"But Jia, I’m sorry to tell you this.","TWN":"可是小佳，怎麼辦呢？"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L46_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"나는 오늘 네 모든 걸 빼앗아 갈 각오로 왔거든.","JPN":"私は今日、あんたのすべてを奪う覚悟で来たのよ。","ENG":"I came here determined to take everything you have and more.","TWN":"我今天可是下定決心要奪走你的一切！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……고모님에 대해선 저도 안타깝지만, 뜻대로 하시게 놔둘 수는 없어요.","JPN":"……叔母様についてはお気の毒に思いますが、\\n思いどおりにさせるわけにはいきません。","ENG":"I’m also sorry, but I won’t allow you to do that.","TWN":"……姑姑的事我也很遺憾，但我無法讓你稱心如意。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"호오, 그래?","JPN":"へえ、そうなの？","ENG":"Oh, is that so?","TWN":"呵呵，是嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그럼 지아야, 더 나은 세상을 위해…….","JPN":"ではユイ、より良い世界のために……","ENG":"Then Jia, for a better world...","TWN":"好吧，小佳，為了更好的未來……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L2_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"저 구속되어 있는 여자를 쏴라.","JPN":"拘束しているあの女を撃て。","ENG":"Shoot that girl tied up over there","TWN":"朝那個被綁起來的女人開槍！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"읏……!","JPN":"うっ……！","ENG":"Ngh...!","TWN":"呃……！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L8_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"리더, 왜 그러세요? 설 수 있겠어요?","JPN":"リーダー、どうしたのですか？　立てますか？","ENG":"Leader, what’s wrong? Can you stand?","TWN":"老大，你怎麼了？站得起來嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"머리가…… 머리가 아파서…….","JPN":"頭が……頭が痛くて……","ENG":"M-my head... It throbs...","TWN":"頭……我的頭好痛……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"야! 리더에게 무슨 짓을 한 거야?!","JPN":"あんた！　リーダーに何をしたの！？","ENG":"Hey! What did you do to Leader?!","TWN":"喂！你對老大做了什麼？！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"회장이 만든 실험체를 조종하려면 두 가지가 필요해.","JPN":"会長が作った実験体を操るために必要な条件は二つ。","ENG":"There are two requirements to control the President’s experiments.","TWN":"要控制會長所製造的實驗體，需要兩個條件。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L16_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"하나는 회장 본인의 목소리. 그리고 두 번째는 지시를 입력하기 위한 명령어지.","JPN":"一つ目は会長本人の声。そして二つ目は指示を入力するためのコマンド。","ENG":"One is his voice... And the other is a trigger phrase.","TWN":"一是會長本人的聲音，二是下命令的指令。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하아…… 하아…… 하아……!!","JPN":"はあ……はあ……はあ……！！","ENG":"Haa... Haagh... Aaagh!!","TWN":"呼呼……呼……呼……！！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"성공한 케이스라 그런가? 꽤 저항하는데?","JPN":"成功したケースだからかしら？　なかなか抵抗するじゃない。","ENG":"Wow, you’re resisting? I guess you really are different from the rest.","TWN":"因為你是成功案例嗎？滿能忍的嘛？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그렇다면…….","JPN":"それなら……","ENG":"Then...","TWN":"既然如此……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"동생이여, 알겠나! 필멸의 악이란 이런 자를 가리키는 말이다!","JPN":"妹よ、わかったか！　必滅の悪とはあのような者を指す言葉だ！","ENG":"Little sister! She is the evil we must vanquish!","TWN":"妹妹，你知道了吧！所謂該死的惡人，是指像她那種的啦！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"나도 알고 있어! 간다!","JPN":"わかってる！　いくよー！","ENG":"I know! Let’s do this!","TWN":"我知道啦！上！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"쳇……! 저것들이 너무 잽싸!","JPN":"ちぇっ！　こいつら、速すぎる！","ENG":"Tch...! They’re too fast!","TWN":"嘖……！他們動作好快！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지금 승부가 갈리는 중요한 순간이거든? 방해하지 말아 줄래, 머저리들아?","JPN":"あんたたち、勝負が決まる大事な瞬間なんだから、\\n邪魔しないでくれる？","ENG":"This is a crucial moment for me, okay? So will you two knuckleheads stop bothering me?","TWN":"現在是很關鍵時刻！你們這群小笨蛋可以不要妨礙我嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"자, 지아야. 더 나은 세상을 위해, 복잡한 생각은 그만둬도 돼.","JPN":"さあユイ、より良い世界のために、複雑なことは考えなくていい。","ENG":"Now, Jia? For a better world, stop thinking for yourself.","TWN":"小佳，為了更好的未來，不要再胡思亂想！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"더 나은 세상을 위해, 내 목소리를 받아들여.","JPN":"より良い世界のために、私の声を受け入れなさい。","ENG":"For a better world, listen and follow my voice.","TWN":"為了更好的未來，聽我的聲音！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"싫어……! 싫어어어……!","JPN":"嫌……！　嫌あああ……！","ENG":"No...! N-never...!","TWN":"不要……！我不要……！！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L49_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"리더! 정신차려요!!","JPN":"リーダー！　しっかりしてください！！","ENG":"Leader! Snap out of it!!","TWN":"老大！你振作一點！！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"악당한테 휘둘리지 마! 리더는 누구보다 가면 카운터처럼 할 수 있잖아!!","JPN":"悪党に振り回されないで！\\nリーダーは誰よりも仮面カウンターのように強い人だよ！！","ENG":"Don’t let her win! You're the closest person I know to the Masked Counter!!","TWN":"不可以任由反派擺布！老大你可以的！你就跟蒙面制裁者一樣厲害！！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"큭……!?","JPN":"くっ……！？","ENG":"Ngh...?!","TWN":"唔……？！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"아깝다! 빗나갔어?!","JPN":"おしい！　外した！？","ENG":"Shoot! I was so close!","TWN":"可惜！差一點！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"저 실험체들보다 호흡은 우리가 더 잘 맞는다! 밀어붙이는 거다, 동생이여!","JPN":"あの実験体たちより私たちのほうが動きがいい！\\n追い込んでやろうじゃないか、妹よ！","ENG":"Our teamwork seems better than that of those things. Let’s keep pressuring them, little sister!","TWN":"我們的默契贏過那些複製人！聯手出擊吧，妹妹！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"신지아!! 내 말 들어!!","JPN":"ヒメノ・ユイ！！　言うことを聞きなさい！！","ENG":"Shin Jia!! Listen to me!!","TWN":"沈佳！！聽我的話！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"더 나은 세상을 위해……!!","JPN":"より良い世界のために……！！","ENG":"For a better world...!!","TWN":"為了更好的未來……！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"오빠가 심어 둔 배신자를 쏴 버려!","JPN":"副会長が潜り込ませた裏切り者を撃て！","ENG":"Shoot the traitor planted by my brother!","TWN":"朝哥哥安排的叛徒開槍！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 할아버님.","JPN":"はい、お祖父様。","ENG":"Yes, Grandfather.","TWN":"是，爺爺。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L23_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"시……. 실장님…….!!!","JPN":"し……室長……！！","ENG":"C-Chief...!!!","TWN":"室……室長……！！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"아, 안 돼!! 실장님!! 실장님, 눈 좀 떠 봐요!!","JPN":"だ、だめ！！　室長！！　室長、目を開けてください！！","ENG":"N-no...!!! CHIEF!!! Please stay with me!!","TWN":"不…不可以！！室長！！你快睜開眼睛！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"대장이…….","JPN":"隊長が……","ENG":"S-she...","TWN":"隊長……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"하, 하하! 하하하하하하!","JPN":"ハ、ハハ！　ハハハハハハッ！","ENG":"Ha! Haha! HAHAHAHAHA!!!","TWN":"哈哈哈哈哈哈哈！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"마침내 손에 넣었어! 최강의 기물을!","JPN":"ついに手に入れたわ！　最強の駒を！","ENG":"She’s finally mine! The most powerful pawn!!","TWN":"最強棋子！終於到手了！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"체스에서 왕은 강할 필요가 없지! 어차피 무엇이든 잘하는 여왕이 있으니까!!","JPN":"チェスでキングが強くなる必要はない！\\n何でもできるクイーンがいるからね！！","ENG":"In chess, the king does not need to be strong! Because the queen can accomplish anything!!","TWN":"在西洋棋的世界裡，國王不強也無所謂！反正有什麼都強的皇后！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지아야, 이제 아버지랑 약속한 대로 널 회장으로 만들어 줄게.","JPN":"ユイ、父さんと約束したとおり、あんたを会長にしてあげる。","ENG":"Jia, as I promised my father, I’ll make you the President.","TWN":"小佳，我會遵守跟爸的約定，讓你當上會長。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"날 위해, 알파트릭스를 송두리째 씹어 삼키기 위해 뼈가 부서지도록 일하는 거야.","JPN":"私のために、アルファトリックスを根こそぎ奪い取るために、\\n馬車馬のごとく働くのよ。","ENG":"You will now work your fingers to the bone for me until I take over Alphatrix!","TWN":"而接下來，你就要努力為我，為吞吃掉阿爾法崔克斯而拼命工作。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"자, 그러면 목격자를 처리해야겠네. 애초에 그걸 위해 불러들인 거기도 하고.","JPN":"さあ、次は目撃者を処理しないとね。そもそも、そのために呼び寄せたのだし。","ENG":"Now, it’s time to get rid of loose ends. That’s why I brought all of you here in the first place.","TWN":"不過現在必須先處理掉目擊者！一開始會找他們來，也是因為要把他們處理掉。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"오, 오빠……. 이제 어떡할 거야?","JPN":"お、お兄ちゃん……どうするの？","ENG":"G-Gabriel... What do we do now?","TWN":"哥哥……現在怎麼辦？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"사나이는, 적에게 등을 보이지 않는 법.","JPN":"男たる者、敵に背を向けぬもの。","ENG":"A real man doesn’t turn his back on his enemies.","TWN":"男子漢是不會輕易向敵人示弱的！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"대답은 정해져 있다! 동료를 우롱하는 악에게 심판을 내려 주지!","JPN":"答えは決まっている！　仲間を愚弄する悪に裁きを下してやろう！","ENG":"There’s only one thing I can do! I will punish the evil who mocks my comrades!","TWN":"答案就是！必須審判愚弄夥伴的壞人！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"앗! 역시 그렇지! 나도 그 말 하려고 했으니까!","JPN":"おっ！　やっぱりそうだね！　私もそれを言おうとした！","ENG":"Huh?! I knew you’d say that! I was going to say the same thing!","TWN":"我就知道！我剛也想講那句台詞！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"……응?","JPN":"……ん？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"이건…….","JPN":"これって……","ENG":"It’s a...","TWN":"這不是……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"가면 카운터 시즈의 외침으로 주박에서 풀려나는 동료와 같은 전개……!","JPN":"仮面カウンターシージの叫びで呪縛から放たれる味方のような展開……！","ENG":"Just like how the Masked Counter’s Siege shout freed his comrades from the curse...!","TWN":"蒙面制裁者裡面的經典場面嗎！大吼一聲後，夥伴就得釋放……!"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE"},{"id":"L2_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"으으……! 실장님의 원수를 갚기 위해 불타오르는 혼을 각성한 오새롬!! 참전한다!!","JPN":"うぅ……！　室長の仇を討つために、\\n燃え上がる魂を覚醒させたケンドウ・アサネ！！　参戦するわ！！","ENG":"Eergh...! I, Oh Saerom, awakened by the burning soul of vengeance for Chief, will also join you!!","TWN":"唔……！現在熱血沸騰的吳芷倫參戰！！我要替室長報仇～～！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"자, 잠깐! 네 동료라고! 그딴 애들 만화에 짜맞추지 마!","JPN":"は？　あいつもあんたの仲間でしょ！　そんなガキの漫画に出てくる悪党じゃないでしょ！","ENG":"W-wait! She’s your leader! Stop pretending like this is some childish cartoon!","TWN":"先等一下！她可是你們的夥伴！勸你們少看那些騙小孩子漫畫吧！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"애들 만화가 뭐가 나빠! 당신은 어린 시절도 없었어?!","JPN":"子どもの漫画のどこが悪いの！　あんたも昔は子どもだったんでしょ！？","ENG":"What’s wrong with kid’s cartoons?! Haven’t you watched one as a kid?!","TWN":"騙小孩的漫畫又怎樣！你沒童年嗎？！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"죄송하지만, 한 가지 오판을 하셨네요.","JPN":"申し訳ありませんが、一つ判断を誤りましたね。","ENG":"I’m sorry, but you’ve underestimated them.","TWN":"不好意思，你誤判一件事。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"오판……? 내가?","JPN":"判断を誤ったですって……？　私が？","ENG":"Underestimate them...? Me?","TWN":"我誤判……？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"저 둘은 바보들이라 평소에는 수준 이하입니다.","JPN":"あの二人はバカなので、そんな理屈は通じませんよ。","ENG":"Those two are stupid as can be under normal circumstances.","TWN":"那兩個笨蛋平時沒什麼用處。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"하지만 분위기에 취하면 보다시피 겁을 상실하고 좋은 엄폐물이 되어 주죠.","JPN":"でも今みたいに雰囲気に酔うと、ご覧のとおり調子に乗って良い掩蔽物になってくれます。","ENG":"But once they’re in the zone, they lose all sense of fear and become great shields.","TWN":"但只要沉醉在氣氛當中，就會變身成天不怕地不怕的掩體，就像你看到的那樣。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그래서, 너도 네 고용주에게 총을 겨누겠다고? 제정신이 아닌 건 너도 마찬가지 같은데!","JPN":"それで、あんたも自分の雇い主に銃口を向けると？\\n正気じゃないのはあんたも同じでしょ！","ENG":"So, you’re going to shoot your employer as well? You sound just as crazy as them!","TWN":"所以你也要把槍瞄準你的雇主嗎？我看你也是腦袋不太正常吧！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"별로요. 리더가 저한테 죽을 사람인가요?","JPN":"別に。リーダーが私に殺されるような人だと思いますか？","ENG":"Not really. Do you really think Leader will die to me?","TWN":"我還好，你覺得老大會這麼輕易死在我手裡嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"그러면, 이런 일개 용병 손에 당할까 봐 걱정스러운 사람에게 질투심을 불태웠던 건가요?","JPN":"じゃなければ、こんな一介の傭兵にやられそうで心配になるような人に\\n嫉妬していたのですか？","ENG":"Or did you become enraged because you were afraid that a mercenary like me would succeed?","TWN":"所以你忌妒的對象，是一個會栽在一個小傭兵手裡的人？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아, 아니, 이……!","JPN":"こ、この……！","ENG":"Why you...!","TWN":"可…呃……！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"리더도 실장님도 부재 중이니 제가 지휘를 대행하겠습니다.","JPN":"リーダーも室長も不在なので、私が指揮を代行します。","ENG":"Since both Leader and Chief are unavailable, I will assume command.","TWN":"老大和室長都不在，現在由我代為發號施令！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"음! 부탁한다!","JPN":"うむ！　頼むぞ！","ENG":"Hmm! Noted!","TWN":"嗯！交給你囉！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"강렬 오새롬 킥, 장전 완료!","JPN":"必殺ケンドウ・アサネ流キック、準備完了！","ENG":"Ultimate Oh Saerom Kick, locked and loaded!","TWN":"必殺吳芷倫踢擊，預備完畢！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"어? 잠깐, 나도 껴도 되는 거야?","JPN":"あれ？　ちょっと待って、私も混ざっていいの？","ENG":"Huh? Hold on, is it okay for me to join in?","TWN":"那個，我也可以加入嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"전원, 프로모션 스타트.","JPN":"全員、プロモーションスタート。","ENG":"Everyone, Promotion start!","TWN":"全員注意，宣傳活動開始！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};